// frontend/src/components/workers/WorkerDashboard.js
import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import api from '../../services/api';
import { useAuth } from '../../contexts/AuthContext';
import { useAlert } from '../../contexts/AlertContext';
import './WorkerDashboard.css';

const WorkerDashboard = () => {
    const { user } = useAuth();
    const alert = useAlert();

    // State declarations
    const [applications, setApplications] = useState([]);
    const [recommendedJobs, setRecommendedJobs] = useState([]);
    const [myVouchers, setMyVouchers] = useState([]);
    const [loadingVouchers, setLoadingVouchers] = useState(false);
    const [selectedVoucher, setSelectedVoucher] = useState(null);
    const [showClaimModal, setShowClaimModal] = useState(false);
    const [claimAmount, setClaimAmount] = useState(0);
    const [claimMethod, setClaimMethod] = useState('bank');
    const [stats, setStats] = useState({
        totalApplications: 0,
        pendingApplications: 0,
        acceptedApplications: 0,
        completedJobs: 0,
        totalEarnings: 0,
        voucherBalance: 0
    });
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    // Pass system states
    const [activePass, setActivePass] = useState(null);
    const [applicationsRemaining, setApplicationsRemaining] = useState(0);
    const [showPassModal, setShowPassModal] = useState(false);

    // Profile completion state
    const [profileCompletion, setProfileCompletion] = useState(0);

    useEffect(() => {
        loadDashboardData();
        loadWorkerVouchers();
        loadActivePass();
        calculateProfileCompletion();
    }, []);

    const loadDashboardData = async () => {
        setLoading(true);
        try {
            // Load applications
            const appsResponse = await api.get('/worker/applications');
            if (appsResponse.data.success) {
                setApplications(appsResponse.data.data);

                // Calculate stats
                const pending = appsResponse.data.data.filter(a => a.status === 'pending').length;
                const accepted = appsResponse.data.data.filter(a => a.status === 'accepted').length;
                const completed = appsResponse.data.data.filter(a => a.job_status === 'completed').length;
                const earnings = appsResponse.data.data
                    .filter(a => a.job_status === 'completed')
                    .reduce((sum, a) => sum + (a.agreed_rate || a.proposed_rate), 0);

                setStats(prev => ({
                    ...prev,
                    totalApplications: appsResponse.data.data.length,
                    pendingApplications: pending,
                    acceptedApplications: accepted,
                    completedJobs: completed,
                    totalEarnings: earnings
                }));
            }

            // Load recommended jobs
            const jobsResponse = await api.get('/jobs?status=posted');
            if (jobsResponse.data.success) {
                setRecommendedJobs(jobsResponse.data.data.slice(0, 4));
            }

        } catch (error) {
            console.error('Error loading dashboard:', error);
            setError('Failed to load dashboard data');
        } finally {
            setLoading(false);
        }
    };

    // Load worker's vouchers (from payments)
    const loadWorkerVouchers = async () => {
        setLoadingVouchers(true);
        try {
            const response = await api.get('/worker/vouchers');
            if (response.data.success) {
                const vouchers = response.data.data;
                setMyVouchers(vouchers);

                // Calculate total voucher balance
                const totalBalance = vouchers
                    .filter(v => v.status === 'active')
                    .reduce((sum, v) => sum + v.balance, 0);

                setStats(prev => ({
                    ...prev,
                    voucherBalance: totalBalance
                }));
            }
        } catch (error) {
            console.error('Error loading vouchers:', error);
        } finally {
            setLoadingVouchers(false);
        }
    };

    // Load worker's active pass
    const loadActivePass = async () => {
        try {
            const response = await api.get('/worker/active-pass');
            if (response.data.success && response.data.data) {
                setActivePass(response.data.data);
                setApplicationsRemaining(response.data.data.applications_remaining);
            }
        } catch (error) {
            console.error('Error loading pass:', error);
        }
    };

    // Calculate profile completion percentage
    const calculateProfileCompletion = async () => {
        try {
            const response = await api.get('/worker/profile-completion');
            if (response.data.success) {
                setProfileCompletion(response.data.data.percentage);
            }
        } catch (error) {
            console.error('Error calculating profile completion:', error);
        }
    };

    // Check if worker can apply
    const canApplyForJob = () => {
        if (!activePass) return false;
        if (activePass.status !== 'active') return false;
        if (!activePass.unlimited && applicationsRemaining <= 0) return false;
        return true;
    };

    // Handle claim voucher
    const handleClaimVoucher = (voucher) => {
        setSelectedVoucher(voucher);
        setClaimAmount(voucher.balance);
        setShowClaimModal(true);
    };

    // Process claim
    const handleProcessClaim = async () => {
        if (!selectedVoucher) return;

        try {
            const response = await api.post('/vouchers/claim', {
                voucher_id: selectedVoucher.id,
                amount: claimAmount,
                claim_method: claimMethod
            });

            if (response.data.success) {
                alert.success(`✅ Successfully claimed R${claimAmount}!`);
                setShowClaimModal(false);
                setSelectedVoucher(null);
                loadWorkerVouchers(); // Refresh vouchers
            }
        } catch (error) {
            console.error('Claim error:', error);
            alert.error(error.response?.data?.message || 'Failed to claim voucher');
        }
    };

    const formatDate = (dateString) => {
        const date = new Date(dateString);
        return date.toLocaleDateString('en-ZA', {
            day: 'numeric',
            month: 'short',
            year: 'numeric'
        });
    };

    const getStatusClass = (status) => {
        switch (status) {
            case 'pending': return 'status-pending';
            case 'accepted': return 'status-accepted';
            case 'rejected': return 'status-rejected';
            default: return '';
        }
    };

    const getVoucherStatusClass = (status) => {
        switch (status) {
            case 'active': return 'voucher-active';
            case 'pending': return 'voucher-pending';
            case 'paid': return 'voucher-paid';
            default: return '';
        }
    };

    const getInitials = (name) => {
        if (!name) return 'W';
        return name.split(' ').map(n => n[0]).join('').toUpperCase().substring(0, 2);
    };

    if (loading) {
        return <div className="loading-spinner">Loading dashboard...</div>;
    }

    return (
        <div className="worker-dashboard">
            <div className="dashboard-container">
                {/* Welcome Section with Profile Summary */}
                <div className="welcome-section">
                    <div className="welcome-content">
                        <div className="welcome-avatar">
                            {user?.profile_picture ? (
                                <img src={user.profile_picture} alt="Profile" />
                            ) : (
                                <div className="avatar-placeholder">
                                    {getInitials(user?.name)}
                                </div>
                            )}
                        </div>
                        <div className="welcome-text">
                            <h1>Welcome back, {user?.name?.split(' ')[0]}! 👋</h1>
                            <p>Here's what's happening with your jobs</p>
                        </div>
                    </div>

                    {/* Profile Completion Bar */}
                    <div className="profile-completion">
                        <div className="completion-header">
                            <span>Profile Completion</span>
                            <span className="completion-percentage">{profileCompletion}%</span>
                        </div>
                        <div className="completion-bar">
                            <div className="completion-progress" style={{ width: `${profileCompletion}%` }}></div>
                        </div>
                        {profileCompletion < 100 && (
                            <Link to={`/workers/${user?.id}`} className="complete-profile-link">
                                Complete your profile to get more jobs →
                            </Link>
                        )}
                    </div>
                </div>

                {/* Pass Status Card */}
                {activePass ? (
                    <div className="pass-status-card">
                        <div className="pass-info">
                            <span className="pass-icon">🎫</span>
                            <div className="pass-details">
                                <h4>Active Pass: {activePass.pass_type === 'monthly' ? 'Monthly' : activePass.pass_type === 'annual' ? 'Annual' : 'Pay-As-You-Go'}</h4>
                                <p className="pass-applications">
                                    {activePass.unlimited ? (
                                        'Unlimited applications'
                                    ) : (
                                        `${applicationsRemaining} of ${activePass.total_applications} applications remaining`
                                    )}
                                </p>
                                {activePass.end_date && (
                                    <p className="pass-expiry">Expires: {formatDate(activePass.end_date)}</p>
                                )}
                            </div>
                        </div>
                        <div className="pass-progress">
                            {!activePass.unlimited && (
                                <div 
                                    className="pass-progress-bar"
                                    style={{ width: `${(activePass.applications_remaining / activePass.total_applications) * 100}%` }}
                                ></div>
                            )}
                        </div>
                        <Link to="/worker/pass" className="btn-manage-pass">
                            Manage Pass →
                        </Link>
                    </div>
                ) : (
                    <div className="no-pass-card">
                        <div className="no-pass-content">
                            <span className="no-pass-icon">🎫</span>
                            <div className="no-pass-text">
                                <h4>No Active Application Pass</h4>
                                <p>Buy a pass to start applying for jobs</p>
                            </div>
                        </div>
                        <Link to="/worker/pass" className="btn-buy-pass">
                            Buy Pass - From R5
                        </Link>
                    </div>
                )}

                {/* Stats Grid */}
                <div className="dashboard-stats">
                    <div className="stat-card">
                        <div className="stat-icon">📋</div>
                        <div className="stat-info">
                            <h3>Total Applications</h3>
                            <span className="stat-number">{stats.totalApplications}</span>
                        </div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-icon">⏳</div>
                        <div className="stat-info">
                            <h3>Pending</h3>
                            <span className="stat-number">{stats.pendingApplications}</span>
                        </div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-icon">✅</div>
                        <div className="stat-info">
                            <h3>Accepted</h3>
                            <span className="stat-number">{stats.acceptedApplications}</span>
                        </div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-icon">💰</div>
                        <div className="stat-info">
                            <h3>Total Earned</h3>
                            <span className="stat-number">R {stats.totalEarnings}</span>
                        </div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-icon">🎫</div>
                        <div className="stat-info">
                            <h3>Voucher Balance</h3>
                            <span className="stat-number">R {stats.voucherBalance}</span>
                        </div>
                    </div>
                </div>

                {error && <div className="error-message">{error}</div>}

                {/* My Applications Section */}
                <div className="section-header">
                    <h2>My Applications</h2>
                    <Link to="/applications" className="view-all">View All →</Link>
                </div>

                {applications.length === 0 ? (
                    <div className="empty-state">
                        <div className="empty-icon">📝</div>
                        <h3>No applications yet</h3>
                        <p>Start applying for jobs to see them here</p>
                        <Link to="/jobs" className="btn-primary">Browse Jobs</Link>
                    </div>
                ) : (
                    <div className="applications-grid">
                        {applications.slice(0, 3).map(app => (
                            <div key={app.id} className="application-card">
                                <div className="application-header">
                                    <span className={`application-status ${getStatusClass(app.status)}`}>
                                        {app.status}
                                    </span>
                                    {app.status === 'accepted' && (
                                        <span className="application-badge">🎉 Hired!</span>
                                    )}
                                </div>
                                <h3>{app.job_title}</h3>
                                <div className="application-details">
                                    <div className="detail-item">
                                        <span>📍</span>
                                        <span>{app.township}</span>
                                    </div>
                                    <div className="detail-item">
                                        <span>📅</span>
                                        <span>Applied {formatDate(app.created_at)}</span>
                                    </div>
                                </div>
                                <div className="application-rate">
                                    <span className="rate-label">Your quote:</span>
                                    <span className="rate-value">R {app.proposed_rate}</span>
                                </div>
                                <div className="application-actions">
                                    <Link to={`/jobs/${app.job_id}`} className="btn-view">
                                        View Job
                                    </Link>
                                    {app.status === 'accepted' && (
                                        <Link to={`/messages/${app.client_id}`} className="btn-message">
                                            💬 Message Client
                                        </Link>
                                    )}
                                </div>
                            </div>
                        ))}
                    </div>
                )}

                {/* Recommended Jobs */}
                <div className="section-header">
                    <h2>Recommended for You</h2>
                    <Link to="/jobs" className="view-all">Browse All →</Link>
                </div>

                <div className="jobs-grid">
                    {recommendedJobs.map(job => (
                        <div key={job.id} className="recommended-job">
                            <div className="job-header">
                                <h3>{job.title}</h3>
                                {job.urgency === 'urgent' && (
                                    <span className="urgent-badge">🚨 Urgent</span>
                                )}
                            </div>
                            <div className="job-meta">
                                <span>📍 {job.township}</span>
                                <span>⏱️ {job.estimated_hours || 'Flexible'}h</span>
                            </div>
                            <p className="job-description">
                                {job.description?.substring(0, 100)}...
                            </p>
                            <div className="job-budget">
                                <span>Budget:</span>
                                <strong>R {job.budget_min} - R {job.budget_max}</strong>
                            </div>
                            <div className="job-footer">
                                <span className="job-date">Posted {formatDate(job.created_at)}</span>
                                <Link to={`/jobs/${job.id}`} className="btn-apply">
                                    View & Apply
                                </Link>
                            </div>
                        </div>
                    ))}
                </div>

                {/* Quick Actions */}
                <div className="quick-actions">
                    <h2>Quick Actions</h2>
                    <div className="actions-grid">
                        <Link to={`/workers/${user?.id}`} className="action-card">
                            <span className="action-icon">👤</span>
                            <span className="action-title">My Profile</span>
                            <span className="action-desc">View and edit your profile</span>
                            {profileCompletion < 100 && (
                                <span className="action-badge">{profileCompletion}%</span>
                            )}
                        </Link>

                        <Link to="/worker/pass" className="action-card">
                            <span className="action-icon">🎫</span>
                            <span className="action-title">Buy Pass</span>
                            <span className="action-desc">Get application passes</span>
                            {!activePass && (
                                <span className="action-badge">Required</span>
                            )}
                        </Link>

                        <Link to="/jobs" className="action-card">
                            <span className="action-icon">🔍</span>
                            <span className="action-title">Find Work</span>
                            <span className="action-desc">Browse available jobs</span>
                            {canApplyForJob() && (
                                <span className="action-badge active">Ready</span>
                            )}
                        </Link>

                        <Link to="/vouchers" className="action-card">
                            <span className="action-icon">💰</span>
                            <span className="action-title">My Vouchers</span>
                            <span className="action-desc">Check your earnings</span>
                            {stats.voucherBalance > 0 && (
                                <span className="action-badge">R{stats.voucherBalance}</span>
                            )}
                        </Link>
                    </div>
                </div>

                {/* Tips Section */}
                <div className="tips-section">
                    <h3>💡 Tips to Get Hired</h3>
                    <div className="tips-grid">
                        <div className="tip-card">
                            <span className="tip-icon">1️⃣</span>
                            <h4>Complete Your Profile</h4>
                            <p>Add skills, rates, and a bio to stand out</p>
                        </div>
                        <div className="tip-card">
                            <span className="tip-icon">2️⃣</span>
                            <h4>Apply to Multiple Jobs</h4>
                            <p>Increase your chances with more applications</p>
                        </div>
                        <div className="tip-card">
                            <span className="tip-icon">3️⃣</span>
                            <h4>Respond Quickly</h4>
                            <p>Clients prefer fast responders</p>
                        </div>
                        <div className="tip-card">
                            <span className="tip-icon">4️⃣</span>
                            <h4>Get Reviews</h4>
                            <p>Good reviews lead to more jobs</p>
                        </div>
                    </div>
                </div>
            </div>

            {/* Claim Voucher Modal */}
            {showClaimModal && selectedVoucher && (
                <div className="modal-overlay" onClick={() => setShowClaimModal(false)}>
                    <div className="claim-modal" onClick={e => e.stopPropagation()}>
                        <div className="modal-header">
                            <h2>💰 Claim Voucher Cash</h2>
                            <button className="modal-close" onClick={() => setShowClaimModal(false)}>×</button>
                        </div>

                        <div className="modal-body">
                            <div className="voucher-summary">
                                <p><strong>Voucher Code:</strong> {selectedVoucher.code}</p>
                                <p><strong>Available Balance:</strong> R {selectedVoucher.balance}</p>
                            </div>

                            <div className="form-group">
                                <label>Amount to Claim</label>
                                <input
                                    type="number"
                                    min="20"
                                    max={selectedVoucher.balance}
                                    value={claimAmount}
                                    onChange={(e) => setClaimAmount(parseInt(e.target.value) || 0)}
                                />
                                <small>Minimum: R20 | Fee: R10</small>
                            </div>

                            <div className="form-group">
                                <label>Claim Method</label>
                                <select 
                                    value={claimMethod}
                                    onChange={(e) => setClaimMethod(e.target.value)}
                                >
                                    <option value="bank">Bank Transfer (1-2 days)</option>
                                    <option value="cash">Cash at Partner Shop (Instant)</option>
                                    <option value="mobile">Mobile Money (Instant)</option>
                                </select>
                            </div>

                            {claimMethod === 'cash' && (
                                <div className="partner-shops">
                                    <h4>Nearby Partner Shops:</h4>
                                    <div className="shop-list">
                                        <div className="shop-item">
                                            <span>Mama Nandi Spaza</span>
                                            <span>📍 Orlando West</span>
                                        </div>
                                        <div className="shop-item">
                                            <span>Bheki Hardware</span>
                                            <span>📍 Diepkloof</span>
                                        </div>
                                    </div>
                                </div>
                            )}

                            <div className="claim-fee">
                                <p>Processing fee: <strong>R10</strong></p>
                                <p>You will receive: <strong>R{claimAmount - 10}</strong></p>
                            </div>

                            <div className="modal-actions">
                                <button 
                                    className="btn-cancel"
                                    onClick={() => setShowClaimModal(false)}
                                >
                                    Cancel
                                </button>
                                <button 
                                    className="btn-confirm-claim"
                                    onClick={handleProcessClaim}
                                >
                                    ✅ Confirm Claim
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default WorkerDashboard;
